scwin.f_setLine = async function () {
  let sbm_LineList = {};
  sbm_LineList.action = "/cm.zz.RetrieveComboCMD.do?sysCd=LineEBC&queryId=retrieveLineEachShpCoCdCombo" + "&param1=" + scwin.loginClntNo + "&param2=" + scwin.userClsCd + "&param3=" + ed_shpCo.getValue();
  let e = await $c.sbm.executeDynamic($p, sbm_LineList);
  ds_LineList.setJSON(e.responseJSON.GAUCE);
  lc_cndLineCd.setSelectedIndex(0);

  // MSC 라인일때 - 2017.11.23 서동원 추가 
  if (scwin.userId == "dwstms") {
    ds_LineList.setJSON([]);
    ds_LineListInfo.setJSON([]);
    ds_LineList.insertRow();
    ds_LineListInfo.insertRow();
    ds_LineList.setCellData(0, "code", "TMSC");
    ds_LineListInfo.setCellData(0, "code", "TMSC");
    ds_LineList.setCellData(0, "name", "DOOWOO SHIPPING CO.,LTD");
    ds_LineListInfo.setCellData(0, "code", "TMSC");
  }
};

//-------------------------------------------------------------------------
// 조회 후, 라인콤보 조회 
//-------------------------------------------------------------------------
scwin.f_setLineInfo = async function (beforeLineCd) {
  let sbm_LineListInfo = {};
  sbm_LineListInfo.action = "/cm.zz.RetrieveComboCMD.do?sysCd=LineEBC&queryId=retrieveLineEachShpCoCdCombo" + "&param1=" + scwin.loginClntNo + "&param2=" + scwin.userClsCd + "&param3=" + ed_shpCo.getValue();
  let e = await $c.sbm.executeDynamic($p, sbm_LineListInfo);
  ds_LineListInfo.setJSON(e.responseJSON.GAUCE);
  if (ds_bookingInfo.getRowCount() > 0) {
    lc_lineCd.setValue(ds_bookingInfo.getCellData(0, "lineCd"));

    // MSC 라인일때 - 2017.11.23 서동원 추가 
    if (scwin.userId == "dwstms") {
      ds_LineList.setJSON([]);
      ds_LineListInfo.setJSON([]);
      ds_LineList.insertRow();
      ds_LineListInfo.insertRow();
      ds_LineList.setCellData(0, "code", "TMSC");
      ds_LineListInfo.setCellData(0, "code", "TMSC");
      ds_LineList.setCellData(0, "name", "DOOWOO SHIPPING CO.,LTD");
      ds_LineListInfo.setCellData(0, "code", "TMSC");
    }
  }
  if (beforeLineCd != null && beforeLineCd != "") {
    lc_cndLineCd.setValue(beforeLineCd);
    lc_lineCd.setValue(beforeLineCd);
  } else {
    lc_cndLineCd.setSelectedIndex(-1);
    lc_lineCd.setSelectedIndex(-1);
  }
};
scwin.sbm_retrieve_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  let cnt = ds_commInfo.getRowCount();
  if (ds_bookingInfo.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_003, ["조회결과"]);
    let beforeLineCd = lc_cndLineCd.getValue();
    await scwin.f_Set("RETRIEVE");
    await scwin.f_setLine();
    scwin.f_setLineInfo(beforeLineCd);
  } else {
    // HSD라인의 경우 당사오더가 진행되면 수정하지 못하도록함
    let rowJson = ds_bookingInfo.getRowJSON(0);
    lc_lineCd.setValue(rowJson.lineCd);
    if (rowJson.lineCd == "HSD" && rowJson.mcomOdrNo != "") {
      $c.gus.cfDisableObjects($p, [btn_update]);
    } else {
      $c.gus.cfEnableObjects($p, [btn_update]);
    }
    await scwin.f_Set("RETRIEVE");
    ds_bookingInfo.setRowPosition(0);
  }

  // 복사여부가 1일때 lineCd와 bookingNo으로 조회한 정보에 대해 복사모드로 세팅
  if (scwin.orderCopy == "1") {
    scwin.f_Set("COPY");

    // bookingNo만 빈값으로 세팅
    ed_cndBookingNo.setValue("");
    ds_bookingInfo.setCellData(0, "bookingNo", "");
    scwin.orderCopy = "0";
  }
  totalRows.setValue(cnt);
  ed_cndBookingNo.focus();
};
